#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <utility>
#include <stack>
#include <unordered_set>
#include <unordered_map>
#include <set>
#include <map>
using namespace std;

const int N = 100010;

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;

    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    void removeNode(TreeNode* root, TreeNode* target) {
        if (root == NULL) {
            return;
        }

        if (root == target) {
            if (root->left == NULL) {
                root = root->right;
            } else if (root->right == NULL) {
                root = root->left;
            } else {
                TreeNode* minNode = getMinNode(root->right);
                root->val = minNode->val;
                removeNode(root->right, minNode);
            }
        }

        removeNode(root->left, target);
        removeNode(root->right, target);
    }

    TreeNode* getMinNode(TreeNode* root) {
        while (root->left) {
            root = root->left;
        }
        return root;
    }
};

int main() {
    int n;
    cin >> n;

    Solution s;

    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;

        if (i == 0) {
            TreeNode* root = new TreeNode(val);
            root = s.removeNode(root, root);
            cout << root->val << endl;
        } else {
            TreeNode* node = new TreeNode(val);
            root->left = node;
            cout << node->val << endl;
        }
    }

    return 0;
}
